function operationSpecSource(operation, requestVar) {
    const pathParams = Object.fromEntries(operation.pathParams.map((parameter) => [parameter.name, propertyAccess(requestVar, parameter.name)]));
    const queryParams = Object.fromEntries(operation.queryParams.map((parameter) => [parameter.name, propertyAccess(requestVar, parameter.name)]));
    const bodyKeys = bodyFieldNames(operation);
    const lines = [
        "{",
        `    method: "${operation.httpMethod}",`,
        `    path: "${operation.path}",`,
    ];
    if (Object.keys(pathParams).length > 0) lines.push(`    pathParams: ${objectExpression(pathParams)},`);
    if (Object.keys(queryParams).length > 0) lines.push(`    queryParams: ${objectExpression(queryParams)},`);
    if (operation.requestBody) {
        if (bodyKeys.length > 0) lines.push(`    body: core.bodyFromRequest(${requestVar} as unknown as Record<string, unknown>, ${JSON.stringify(bodyKeys)}),`);
        else lines.push(`    body: (${requestVar} as { body?: unknown }).body,`);
        lines.push(`    contentType: "${operation.requestBody.contentType}",`);
        if (operation.requestBody.multipart) lines.push("    multipart: true,");
    }
    lines.push(`    responseType: "${operation.response.type}",`);
    lines.push("}");
    return lines.join("\n");
}

function objectExpression(entries) {
    const lines = ["{"];
    for (const [key, value] of Object.entries(entries)) lines.push(`        ${JSON.stringify(key)}: ${value},`);
    lines.push("    }");
    return lines.join("\n");
}

async function writeClient(model, outDir) {
    const imports = model.resources
        .map((resource) => `import { ${toPascal(resource)}Client } from "./api/resources/${resource}/client/Client.js";`)
        .join("\n");
    const fields = model.resources.map((resource) => `protected _${resource}: ${toPascal(resource)}Client | undefined;`).join("\n    ");
    const getters = model.resources
        .map((resource) => `public get ${resource}(): ${toPascal(resource)}Client { return (this._${resource} ??= new ${toPascal(resource)}Client(this._options)); }`)
        .join("\n\n    ");
    await write(outDir, "Client.ts", `${GENERATED_BANNER}${imports}\nimport type { BaseClientOptions, BaseRequestOptions } from "./BaseClient.js";\nimport { type NormalizedClientOptionsWithAuth, normalizeClientOptionsWithAuth } from "./BaseClient.js";\nimport * as core from "./core/index.js";\n\nexport declare namespace ClockifyApiClient {\n    export type Options = BaseClientOptions;\n    export interface RequestOptions extends BaseRequestOptions {}\n}\n\nexport class ClockifyApiClient {\n    protected readonly _options: NormalizedClientOptionsWithAuth<ClockifyApiClient.Options>;\n    ${fields}\n\n    constructor(options: ClockifyApiClient.Options) { this._options = normalizeClientOptionsWithAuth(options); }\n\n    ${getters}\n\n    public async fetch(input: Request | string | URL, init?: RequestInit, requestOptions?: core.PassthroughRequest.RequestOptions): Promise<Response> {\n        return core.makePassthroughRequest(input, init, {\n            baseUrl: this._options.baseUrl ?? this._options.environment,\n            headers: this._options.headers,\n            timeoutInSeconds: this._options.timeoutInSeconds,\n            maxRetries: this._options.maxRetries,\n            fetch: this._options.fetch,\n            logging: this._options.logging,\n            getAuthHeaders: async () => (await this._options.authProvider.getAuthRequest()).headers,\n        }, requestOptions);\n    }\n}\n`);
}

function requestFields(model, operation) {
    const fields = [];
    fields.push(...requestNonBodyFields(model, operation));
    const existing = new Set(fields.map((field) => field.name));
    for (const field of bodyFields(model, operation)) {
        if (existing.has(field.name)) continue;
        fields.push(field);
    }
    return fields;
}

function requestNonBodyFields(model, operation) {
    const fields = [];
    for (const parameter of operation.pathParams) fields.push(parameterField(parameter, true, model));
    for (const parameter of operation.queryParams) fields.push(parameterField(parameter, parameter.required === true, model));
    return fields;
}

function bodyFields(model, operation) {
    const schema = deref(operation.requestBody?.schema, model);
    if (!schema) return [];
    return schemaProperties(schema, model);
}

function bodyFieldNames(operation) {
    return operation.requestBody ? bodyFields(globalModelForBodyFields, operation).map((field) => field.name) : [];
}

let globalModelForBodyFields;

function schemaProperties(schema, model) {
    const resolved = deref(schema, model);
    const merged = mergeComposedSchema(resolved, model);
    const properties = merged.properties ?? {};
    const required = new Set(merged.required ?? []);
    return Object.entries(properties).map(([name, property]) => ({
        name,
        required: required.has(name),
        type: typeFromSchema(property, model),
        description: property.description,
    }));
}

function mergeComposedSchema(schema, model) {
    if (!schema) return {};
    const parts = [...(schema.allOf ?? []), ...(schema.anyOf?.length === 1 ? schema.anyOf : [])].map((part) => deref(part, model));
    if (parts.length === 0) return schema;
    const merged = { ...schema, properties: { ...(schema.properties ?? {}) }, required: [...(schema.required ?? [])] };
    for (const part of parts) {
        Object.assign(merged.properties, part.properties ?? {});
        merged.required.push(...(part.required ?? []));
    }
    return merged;
}

function parameterField(parameter, required, model) {
    return {
        name: parameter.name,
        required,
        type: typeFromSchema(parameter.schema ?? {}, model),
        description: parameter.description,
    };
}

function fieldLine(field) {
    const optional = field.required ? "" : "?";
    const name = identifier(field.name) ? field.name : JSON.stringify(field.name);
    const description = field.description ? `    /** ${field.description.replace(/\*\//g, "* /")} */\n` : "";
    return `${description}    ${name}${optional}: ${field.type};`;
}

function typeFromSchema(schema, model) {
    const sourceSchema = schema;
    if (schema?.$ref) {
        const refName = refToName(schema.$ref);
        const type = schema.$ref.split("/").length === 4 ? `ClockifyApi.${refName}` : typeFromSchema(deref(schema, model), model);
        return withNullable(type, sourceSchema);
    }
    const resolved = deref(schema, model);
    if (!resolved) return "unknown";
    let type;
    if (resolved.enum) type = unionTypes(resolved.enum.map(literal));
    else if (resolved.oneOf || resolved.anyOf) type = unionTypes([...(resolved.oneOf ?? []), ...(resolved.anyOf ?? [])].map((part) => typeFromSchema(part, model)));
    else if (resolved.allOf) type = resolved.allOf.map((part) => typeFromSchema(part, model)).join(" & ") || "unknown";
    else if (resolved.type === "array") type = `${typeFromSchema(resolved.items, model)}[]`;
    else if (resolved.type === "integer" || resolved.type === "number") type = "number";
    else if (resolved.type === "boolean") type = "boolean";
    else if (resolved.type === "null") type = "null";
    else if (resolved.type === "string") {
        if (["binary", "base64", "byte"].includes(resolved.format)) {
            type = "Blob | File | Buffer | Uint8Array | string";
        } else {
            type = "string";
        }
    } else if (resolved.type === "object" || resolved.properties) {
        if (resolved.additionalProperties && !resolved.properties) {
            type = `Record<string, ${resolved.additionalProperties === true ? "unknown" : typeFromSchema(resolved.additionalProperties, model)}>`;
        } else {
            type = "Record<string, unknown>";
        }
    }
    return withNullable(type ?? "unknown", sourceSchema, resolved);
}

function primitiveType(type) {
    return type === "string" || type === "integer" || type === "number" || type === "boolean" || type === "null";
}

function withNullable(type, ...schemas) {
    if (!schemas.some((schema) => schema?.nullable === true)) return type;
    return unionTypes([type, "null"]);
}

function unionTypes(types) {
    const flattened = [];
    for (const type of types) {
        for (const part of String(type)
            .split(" | ")
            .map((entry) => entry.trim())
            .filter(Boolean)) {
            if (!flattened.includes(part)) flattened.push(part);
        }
    }
    return flattened.join(" | ") || "unknown";
}

function responseTypeFromOperation(operation) {
    if (operation.response.type === "void") return "void";
    if (operation.response.type === "binary") return "core.BinaryResponse";
    return typeFromSchema(operation.response.schema, globalModelForBodyFields);
}

function deref(schema, model) {
    if (!schema) return schema;
    if (schema.$ref?.startsWith("#/")) {
        const parts = schema.$ref.slice(2).split("/");
        let current = model.doc;
        for (const part of parts) current = current?.[part];
        return current ?? schema;
    }
    return schema;
}

function literal(value) {
    return JSON.stringify(value);
}

function tagToResource(tag) {
    return toCamel(tag.replace(/[()]/g, " "));
}

function toCamel(value) {
    const words = wordsFrom(value);
    if (words.length === 0) return "value";
    return words[0].toLowerCase() + words.slice(1).map(capitalize).join("");
}

function toPascal(value) {
    return wordsFrom(value).map(capitalize).join("") || "Value";
}

function wordsFrom(value) {
    return String(value)
        .replace(/([a-z0-9])([A-Z])/g, "$1 $2")
        .split(/[^A-Za-z0-9]+/)
        .filter(Boolean);
}

function capitalize(value) {
    return value.charAt(0).toUpperCase() + value.slice(1);
}

function refToName(ref) {
    return ref.split("/").at(-1);
}

function propertyAccess(objectName, propertyName) {
    return identifier(propertyName) ? `${objectName}.${propertyName}` : `${objectName}[${JSON.stringify(propertyName)}]`;
}

function identifier(name) {
    return /^[A-Za-z_$][A-Za-z0-9_$]*$/.test(name);
}

function indent(text, spaces) {
    const prefix = " ".repeat(spaces);
    return text
        .split("\n")
        .map((line) => (line ? prefix + line : line))
        .join("\n");
}

async function write(outDir, relativePath, text) {
    const absolute = path.join(outDir, relativePath);
    await writeFileWithDir(absolute, text);
}

async function writeReceipt(absolute, receipt) {
    await writeFileWithDir(absolute, `${JSON.stringify(receipt, null, 2)}\n`);
}

async function writeFileWithDir(absolute, text) {
    await import("node:fs/promises").then(async ({ mkdir }) => mkdir(path.dirname(absolute), { recursive: true }));
    await writeFile(absolute, text.endsWith("\n") ? text : `${text}\n`);
}

async function compareTrees(left, right) {
    if (!existsSync(right)) return [`missing ${path.relative(root, right)}`];
    const leftFiles = await listFiles(left);
    const rightFiles = await listFiles(right);
    const all = [...new Set([...leftFiles, ...rightFiles])].sort();
    const diff = [];
    for (const file of all) {
        if (!leftFiles.includes(file)) diff.push(`extra file ${file}`);
        else if (!rightFiles.includes(file)) diff.push(`missing file ${file}`);
        else {
            const leftText = await readFile(path.join(left, file), "utf8");
            const rightText = await readFile(path.join(right, file), "utf8");
            if (leftText !== rightText) diff.push(`changed ${file}`);
        }
    }
    return diff;
}

async function listFiles(dir) {
    const files = [];
    async function walk(current) {
        for (const entry of await readdir(current)) {
            const absolute = path.join(current, entry);
            const info = await stat(absolute);
            if (info.isDirectory()) await walk(absolute);
            else if (info.isFile()) files.push(path.relative(dir, absolute).replace(/\\/g, "/"));
        }
    }
    await walk(dir);
    return files;
}

if (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {
    await main();
}
